--- a/auth-service/connections/manager.go
+++ b/auth-service/connections/manager.go
+type ConnectionManager struct {
+    activeConns map[string][]*Connection
+    mu          sync.Mutex
+}
+
+func (cm *ConnectionManager) Failover(fromAZ, toAZ string) error {
+    cm.mu.Lock()
+    defer cm.mu.Unlock()
+    // Close ALL existing connections first to prevent leaks
+    for az, conns := range cm.activeConns {
+        for _, conn := range conns {
+            conn.Close()
+        }
+        delete(cm.activeConns, az)
+    }
+    // Now open new connections to target AZ
+    newConns, err := cm.dialAZ(toAZ)
+    if err != nil {
+        // BUG: if dialAZ fails, we have 0 connections and no way to recover
+        // without a restart since we already closed all old connections
+        return fmt.Errorf("failover to %s failed: %w", toAZ, err)
+    }
+    cm.activeConns[toAZ] = newConns
+    return nil
+}

--- a/data-service/db/replicas.go
+++ b/data-service/db/replicas.go
+func SetupReplica(az string) (*sql.DB, error) {
+    return sql.Open("postgres", replicaConnStr(az))
+}
